import React from 'react';
import { Search, MapPin, Tag } from 'lucide-react';

const Home = () => {
  return (
    <div style={{ background: '#f8fafc', minHeight: '90vh' }}>
      {/* SECCIÓN BUSCADOR */}
      <div style={heroSection}>
        <h1 style={{ color: 'white', fontSize: '2.5rem', marginBottom: '20px' }}>¿Qué producto buscas hoy?</h1>
        <div style={searchContainer}>
          <Search color="#94a3b8" />
          <input type="text" placeholder="Ej: Aceite de girasol, Cerveza..." style={searchInput} />
          <button style={btnSearch}>Buscar Ofertas</button>
        </div>
      </div>

      {/* RESULTADOS RÁPIDOS */}
      <div style={{ padding: '40px 8%' }}>
        <h3>Ofertas destacadas en Tucumán</h3>
        <div style={gridOfertas}>
          {/* Ejemplo de tarjeta de oferta para el cliente */}
          <div style={cardOferta}>
            <div style={badgeVence}>Vence en 2 días</div>
            <img src="https://via.placeholder.com/150" alt="producto" style={imgStyle} />
            <h4 style={{ margin: '10px 0 5px' }}>Aceite Natura 1.5L</h4>
            <p style={precioStyle}>$1.200</p>
            <div style={localInfo}>
              <MapPin size={14} /> <span>Mr. Drink - 2.5 km</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

/* --- ESTILOS --- */
const heroSection = { background: '#1e293b', padding: '80px 5%', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center' };
const searchContainer = { display: 'flex', alignItems: 'center', background: 'white', padding: '10px 10px 10px 20px', borderRadius: '15px', width: '100%', maxWidth: '600px', gap: '10px' };
const searchInput = { border: 'none', outline: 'none', flex: 1, fontSize: '1.1rem' };
const btnSearch = { background: '#e67e22', color: 'white', border: 'none', padding: '12px 25px', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };
const gridOfertas = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px', marginTop: '20px' };
const cardOferta = { background: 'white', padding: '15px', borderRadius: '20px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', position: 'relative' };
const badgeVence = { position: 'absolute', top: '10px', left: '10px', background: '#fee2e2', color: '#ef4444', padding: '4px 8px', borderRadius: '5px', fontSize: '0.7rem', fontWeight: 'bold' };
const imgStyle = { width: '100%', height: '150px', objectFit: 'contain', borderRadius: '10px' };
const precioStyle = { fontSize: '1.4rem', fontWeight: '800', color: '#1e293b', margin: '5px 0' };
const localInfo = { display: 'flex', alignItems: 'center', gap: '5px', color: '#64748b', fontSize: '0.8rem' };

export default Home;
